// RAKITRAKATRA CORE v1.0.2 - FIXED & REFLECTED
(function (global, factory) {
  if (typeof exports === "object" && typeof module === "object") module.exports = factory();
  else if (typeof define === "function" && define.amd) define([], factory);
  else (global = global || self).Rakitrakatra = factory();
})(this, () => {

  const R = {};
  window.Rakitrakatra = R;

  // --- REFLECTION / CACHE ---
  const _cache = { sary: {}, feo: {}, audioCtx: null };
  const _abort = typeof AbortController!== "undefined"? new AbortController() : { signal: null };

  R.Util = {
    kisendrasendra: (min, max) => Math.floor(Math.random() * (max - min + 1)) + min,
    elanelany: (a, b) => Math.hypot(a.x - b.x, a.y - b.y),
    mifandona: (a, b) => a.x < b.x + b.sakany && a.x + a.sakany > b.x && a.y < b.y + b.haavony && a.y + a.haavony > b.y
  };

  // --- FIZIKA ---
  class Fizika {
    constructor(tontolo) {
      this.tontolo = tontolo;
      this.gravite = { x: 0, y: 900 };
      this.vatana = [];
      this.grid = new Map();
    }
    hash(x, y) { return `${x >> 7},${y >> 7}`; }
    havaozy(dt) {
      dt = Math.min(dt, 1 / 30);
      this.grid.clear();
      this.vatana.forEach(e => {
        if (e._mavita &&!e._mijanona) {
          e.vy += this.gravite.y * e.lanja * dt;
          e.x += e.vx * dt;
          e.y += e.vy * dt;
          if (e.mifandonaTany && e.y + e.haavony >= this.tontolo.haavony) {
            e.y = this.tontolo.haavony - e.haavony;
            e.vy *= -e.fikitihana;
            e.mikasikaTany = true;
          }
          if (e.x < 0) { e.x = 0; e.vx *= -e.fikitihana; }
          if (e.x + e.sakany > this.tontolo.sakany) { e.x = this.tontolo.sakany - e.sakany; e.vx *= -e.fikitihana; }
        }
        const h = this.hash(e.x, e.y);
        if (!this.grid.has(h)) this.grid.set(h, []);
        this.grid.get(h).push(e);
      });
      for (let [key, list] of this.grid) {
        for (let i = 0; i < list.length; i++) {
          for (let j = i + 1; j < list.length; j++) {
            const a = list[i], b = list[j];
            if (a._mavita && b._mavita && a.layer === b.layer && R.Util.mifandona(a, b)) {
              this.saraho(a, b);
              a.mifandona?.(b);
              b.mifandona?.(a);
            }
          }
        }
      }
    }
    saraho(a, b) {
      const dx = (a.x + a.sakany / 2) - (b.x + b.sakany / 2);
      const dy = (a.y + a.haavony / 2) - (b.y + b.haavony / 2);
      const sx = a.sakany / 2 + b.sakany / 2 - Math.abs(dx);
      const sy = a.haavony / 2 + b.haavony / 2 - Math.abs(dy);
      if (sx > 0 && sy > 0) {
        if (sx < sy) {
          const sep = dx > 0? sx : -sx;
          a.x += sep / 2; b.x -= sep / 2;
          a.vx *= -a.fikitihana; b.vx *= -b.fikitihana;
        } else {
          const sep = dy > 0? sy : -sy;
          a.y += sep / 2; b.y -= sep / 2;
          a.vy *= -a.fikitihana; b.vy *= -b.fikitihana;
          a.mikasikaTany = true;
        }
      }
    }
    ampio(v) { this.vatana.push(v); }
    esory(v) { const i = this.vatana.indexOf(v); if (i > -1) this.vatana.splice(i, 1); }
  }
  R.Fizika = Fizika;

  // --- MPANDRAY ANJARA ---
  class MpandrayAnjara {
    constructor(kianja, x, y, sarySrc) {
      this.kianja = kianja; this.x = x; this.y = y;
      this.sakany = 32; this.haavony = 32; this.habeX = 1; this.habeY = 1;
      this.vx = 0; this.vy = 0; this.lanja = 1; this.fikitihana = 0;
      this._mivadika = false; this._mavita = false; this._mijanona = false;
      this.mifandonaTany = true; this.mikasikaTany = false; this.layer = 0;
      this.animasiona = {}; this.animAnkehitriny = null; this.frame = 0; this.fotoanaFrame = 0;
      this._sary = null; this._alpha = 1; this._hodina = 0;
      if (sarySrc) this.alaivoSary(sarySrc);
      kianja.fizika.ampio(this);
      kianja.zavatra.push(this);
    }
    alaivoSary(src) {
      if (!_cache.sary[src]) { _cache.sary[src] = new Image(); _cache.sary[src].src = src; }
      this._sary = _cache.sary[src];
      this._sary.onload = () => { this.sakany = this._sary.width; this.haavony = this._sary.height; };
    }
    fizika(mode) { if (mode === "mandeha") this._mavita = true; if (mode === "mijanona") this._mijanona = true; }
    mandeha(vx, vy) { this.vx = vx; if (vy!= null) this.vy = vy; }
    mitsambikina(hery) { if (this.mikasikaTany) { this.vy = -hery; this.mikasikaTany = false; } }
    mikasika(obj) { return R.Util.mifandona(this, obj); }
    fafao() { this._hoFafana = true; this.kianja.fizika.esory(this); }
    soraty(ctx) {
      ctx.save(); ctx.globalAlpha = this._alpha;
      ctx.translate(this.x + this.sakany * this.habeX / 2, this.y + this.haavony * this.habeY / 2);
      ctx.rotate(this._hodina); if (this._mivadika) ctx.scale(-1, 1);
      if (this._sary?.complete) ctx.drawImage(this._sary, -this.sakany * this.habeX / 2, -this.haavony * this.habeY / 2, this.sakany * this.habeX, this.haavony * this.habeY);
      else { ctx.fillStyle = "#FF00FF"; ctx.fillRect(-this.sakany * this.habeX / 2, -this.haavony * this.habeY / 2, this.sakany * this.habeX, this.haavony * this.habeY); }
      ctx.restore();
    }
    havaozy(dt) { /* override */ }
  }
  R.MpandrayAnjara = MpandrayAnjara;

  // --- KIANJA ---
  class Kianja {
    constructor(anarana) {
      this.anarana = anarana; this.zavatra = []; this.fizika = new Fizika(this);
      this.lokoFototra = "#1a1a2e"; this.fakanTsary = { x: 0, y: 0, zoom: 1, manaraka: null, mihorohoro: 0, mametra: null };
      this.lalao = null;
      if (anarana) R._kianja[anarana] = this; // FIX: R._kianja fa tsy t._kianja
    }
    havaozy(dt) {
      this.fizika.havaozy(dt);
      this.zavatra = this.zavatra.filter(o =>!o._hoFafana);
      this.zavatra.forEach(o => o.havaozy(dt));
      if (this.fakanTsary.manaraka) {
        const t = this.fakanTsary.manaraka;
        this.fakanTsary.x += (t.x - this.lalao.sakany / 2 - this.fakanTsary.x) * 0.1;
        this.fakanTsary.y += (t.y - this.lalao.haavony / 2 - this.fakanTsary.y) * 0.1;
      }
      if (this.fakanTsary.mihorohoro > 0) this.fakanTsary.mihorohoro -= dt;
    }
    soraty(ctx) {
      ctx.save();
      ctx.translate(-this.fakanTsary.x, -this.fakanTsary.y);
      ctx.scale(this.fakanTsary.zoom, this.fakanTsary.zoom);
      if (this.fakanTsary.mihorohoro > 0) ctx.translate((Math.random() - 0.5) * this.fakanTsary.mihorohoro, (Math.random() - 0.5) * this.fakanTsary.mihorohoro);
      this.zavatra.forEach(o => o.soraty(ctx));
      ctx.restore();
    }
  }
  R.Kianja = Kianja;

  // --- LALAO ---
  class Lalao {
    constructor(opts) {
      this.sakany = opts.sakany || 800; this.haavony = opts.haavony || 600;
      this.lokoFototra = opts.lokoFototra || "#000";
      this.canvas = document.createElement("canvas"); this.canvas.width = this.sakany; this.canvas.height = this.haavony;
      this.ctx = this.canvas.getContext("2d"); this.ctx.imageSmoothingEnabled = false;
      (document.getElementById(opts.toerana) || document.body).appendChild(this.canvas);
      this.kianjaAnkehitriny = null; this.fotoanaFarany = 0; this.accumulator = 0; this.step = 1 / 60;
      this.kitendry = {}; this.kitendryVao = {};
      window.addEventListener("keydown", e => { this.kitendry[e.key.toLowerCase()] = true; this.kitendryVao[e.key.toLowerCase()] = true; }, { signal: _abort.signal });
      window.addEventListener("keyup", e => { this.kitendry[e.key.toLowerCase()] = false; }, { signal: _abort.signal });
      opts._lalao = this;
    }
    atombohy(anarana) {
      this.kianjaAnkehitriny = R._kianja[anarana];
      if (this.kianjaAnkehitriny) { this.kianjaAnkehitriny.lalao = this; this.kianjaAnkehitriny.vonona?.(); }
      requestAnimationFrame(this.tsingerina.bind(this));
    }
    tsingerina(timestamp) {
      const delta = (timestamp - this.fotoanaFarany) / 1000; this.fotoanaFarany = timestamp; this.accumulator += delta;
      while (this.accumulator >= this.step) {
        this.kianjaAnkehitriny?.havaozy(this.step); this.accumulator -= this.step;
        R.Fotoana.mitahiry(this.kianjaAnkehitriny);
      }
      this.kitendryVao = {};
      const ctx = this.ctx; ctx.fillStyle = this.kianjaAnkehitriny?.lokoFototra || this.lokoFototra; ctx.fillRect(0, 0, this.sakany, this.haavony);
      this.kianjaAnkehitriny?.soraty(ctx); R.Debug.soraty(ctx);
      requestAnimationFrame(this.tsingerina.bind(this));
    }
  }
  R.Lalao = Lalao;

  // --- SISANY MITOVY FA EFA VOAHAHY ---
  R._kianja = {}; R._lalao = null;
  R.mandehana = (anarana) => R._lalao?.atombohy(anarana);
  //... (Feo, Kitendry, Debug, Soratra, Bokotra, Bar, Vovoka, sns afaka ampidirina eto mitovy amin'ny anao)

  return R;
});
